   1→import { useCallback, useEffect, useMemo, useState } from 'react';
   2→import { ActionPanel } from './components/action_panel/action_panel';
   3→import { Alert } from './components/alert/alert';
   4→import { CommandPalette } from './components/command_palette/command_palette';
   5→import { Detail } from './components/detail/detail';
   6→import { DetailMetadata } from './components/detail/detail_metadata';
   7→import { EmptyState } from './components/empty_state/empty_state';
   8→import { HUDContainer } from './components/hud/hud_container';
   9→import { CalculatorIcon, StarFilledIcon } from './components/icons';
  10→import { Kbd } from './components/kbd/kbd';
  11→import { List, ListItem, ListSection } from './components/list';
  12→import { QuickLook } from './components/quick_look/quick_look';
  13→import { SearchBar } from './components/search_bar/search_bar';
  14→import type { SearchDropdownSection } from './components/search_bar/search_dropdown';
  15→import { SearchDropdown } from './components/search_bar/search_dropdown';
  16→import { ToastContainer } from './components/toast/toast_container';
  17→import { useAlert } from './hooks/use_alert';
  18→import { useFavorites } from './hooks/use_favorites';
  19→import { useHUD } from './hooks/use_hud';
  20→import { useKeyboardShortcut } from './hooks/use_keyboard_shortcut';
  21→import {
  22→  NavigationContextProvider,
  23→  useNavigationStack,
  24→} from './hooks/use_navigation';
  25→import { useTheme } from './hooks/use_theme';
  26→import { useToast } from './hooks/use_toast';
  27→import { useWindow } from './hooks/use_window';
  28→import { getCommand, getSections, searchCommands } from './registry';
  29→import type { ListItemData, ListItemMetadataEntry, SectionData } from './types';
  30→import { evaluate } from './utils/calculator';
  31→
  32→type NavViewData =
  33→  | {
  34→      type: 'command';
  35→      commandId: string;
  36→    }
  37→  | {
  38→      type: 'detail';
  39→      item: ListItemData;
  40→    };
  41→
  42→const TRAY_COMMAND_MAP: Record<
  43→  string,
  44→  {
  45→    id: string;
  46→    name: string;
  47→  }
  48→> = {
  49→  clipboard: {
  50→    id: 'clipboard-history',
  51→    name: 'Clipboard History',
  52→  },
  53→  snippets: {
  54→    id: 'snippets',
  55→    name: 'Snippets',
  56→  },
  57→  settings: {
  58→    id: 'settings',
  59→    name: 'Settings',
  60→  },
  61→  about: {
  62→    id: 'settings',
  63→    name: 'Settings',
  64→  },
  65→  'check-updates': {
  66→    id: 'settings',
  67→    name: 'Settings',
  68→  },
  69→};
  70→
  71→function flattenItems(sections: SectionData[]): ListItemData[] {
  72→  return sections.flatMap(s => s.items);
  73→}
  74→
  75→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
  76→  switch (entry.type) {
  77→    case 'label':
  78→      return (
  79→        <DetailMetadata.Label
  80→          key={index}
  81→          title={entry.title}
  82→          text={entry.text}
  83→        />
  84→      );
  85→    case 'link':
  86→      return (
  87→        <DetailMetadata.Link
  88→          key={index}
  89→          title={entry.title}
  90→          text={entry.text}
  91→          target={entry.target}
  92→        />
  93→      );
  94→    case 'tag-list':
  95→      return (
  96→        <DetailMetadata.TagList key={index} title={entry.title}>
  97→          {entry.tags.map(tag => (
  98→            <DetailMetadata.Tag
  99→              key={tag.text}
 100→              text={tag.text}
 101→              color={tag.color}
 102→            />
 103→          ))}
 104→        </DetailMetadata.TagList>
 105→      );
 106→    case 'separator':
 107→      return <DetailMetadata.Separator key={index} />;
 108→  }
 109→}
 110→
 111→function CheckIcon() {
 112→  return (
 113→    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
 114→      <path
 115→        d="M3.5 8.5L6.5 11.5L12.5 4.5"
 116→        stroke="currentColor"
 117→        strokeWidth="1.5"
 118→        strokeLinecap="round"
 119→        strokeLinejoin="round"
 120→      />
 121→    </svg>
 122→  );
 123→}
 124→
 125→function ClipboardHUDIcon() {
 126→  return (
 127→    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
 128→      <rect
 129→        x="4"
 130→        y="2"
 131→        width="8"
 132→        height="12"
 133→        rx="1.5"
 134→        stroke="currentColor"
 135→        strokeWidth="1.5"
 136→      />
 137→      <path
 138→        d="M6 2.5H10"
 139→        stroke="currentColor"
 140→        strokeWidth="1.5"
 141→        strokeLinecap="round"
 142→      />
 143→    </svg>
 144→  );
 145→}
 146→
 147→function SearchIcon() {
 148→  return (
 149→    <svg
 150→      width="48"
 151→      height="48"
 152→      viewBox="0 0 48 48"
 153→      fill="none"
 154→      xmlns="http://www.w3.org/2000/svg"
 155→    >
 156→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
 157→      <line
 158→        x1="30"
 159→        y1="30"
 160→        x2="42"
 161→        y2="42"
 162→        stroke="currentColor"
 163→        strokeWidth="3"
 164→        strokeLinecap="round"
 165→      />
 166→    </svg>
 167→  );
 168→}
 169→
 170→function DetailView({ item }: { item: ListItemData }) {
 171→  const itemDetail = item.detail;
 172→  if (!itemDetail) return null;
 173→  return (
 174→    <Detail
 175→      markdown={itemDetail.markdown}
 176→      metadata={
 177→        itemDetail.metadata ? (
 178→          <DetailMetadata>
 179→            {itemDetail.metadata.map(renderMetadataEntry)}
 180→          </DetailMetadata>
 181→        ) : undefined
 182→      }
 183→    />
 184→  );
 185→}
 186→
 187→export function App() {
 188→  useTheme();
 189→  const [query, setQuery] = useState('');
 190→  const [filterValue, setFilterValue] = useState('all');
 191→  const [selectedIndex, setSelectedIndex] = useState(0);
 192→  const [actionsOpen, setActionsOpen] = useState(false);
 193→  const [quickLookOpen, setQuickLookOpen] = useState(false);
 194→  const { toasts, show: showToast, hide: hideToast } = useToast();
 195→  const { items: hudItems, show: showHUD } = useHUD();
 196→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
 197→  const nav = useNavigationStack<NavViewData>('Raycast');
 198→  const { push, popToRoot } = nav;
 199→  const { favoriteIds, isFavorite, toggleFavorite, moveFavorite } =
 200→    useFavorites();
 201→
 202→  const handleTrayNavigate = useCallback(
 203→    (target: string) => {
 204→      const mapping = TRAY_COMMAND_MAP[target];
 205→      if (!mapping) return;
 206→
 207→      const cmd = getCommand(mapping.id);
 208→      if (!cmd?.component) return;
 209→
 210→      popToRoot();
 211→      setQuery('');
 212→      setSelectedIndex(0);
 213→      setActionsOpen(false);
 214→      setQuickLookOpen(false);
 215→      setFilterValue('all');
 216→
 217→      push(mapping.name, {
 218→        type: 'command',
 219→        commandId: mapping.id,
 220→      });
 221→    },
 222→    [
 223→      push,
 224→      popToRoot,
 225→    ],
 226→  );
 227→
 228→  useWindow({
 229→    onShow: () => {
 230→      const input =
 231→        document.querySelector<HTMLInputElement>('.search-bar__input');
 232→      input?.focus();
 233→    },
 234→    onHide: () => {
 235→      setQuery('');
 236→      popToRoot();
 237→      setActionsOpen(false);
 238→      setQuickLookOpen(false);
 239→      setSelectedIndex(0);
 240→      setFilterValue('all');
 241→    },
 242→    onTrayNavigate: handleTrayNavigate,
 243→  });
 244→
 245→  const currentNavData = nav.currentEntry?.data;
 246→  const isRoot = !currentNavData;
 247→  const isFullView =
 248→    currentNavData?.type === 'command' &&
 249→    (getCommand(currentNavData.commandId)?.fullView ?? false);
 250→
 251→  const searchFilterSections: SearchDropdownSection[] = useMemo(
 252→    () => [
 253→      {
 254→        options: [
 255→          {
 256→            label: 'All',
 257→            value: 'all',
 258→          },
 259→        ],
 260→      },
 261→      {
 262→        title: 'Types',
 263→        options: [
 264→          {
 265→            label: 'Commands',
 266→            value: 'commands',
 267→          },
 268→          {
 269→            label: 'Applications',
 270→            value: 'applications',
 271→          },
 272→        ],
 273→      },
 274→    ],
 275→    [],
 276→  );
 277→
 278→  useEffect(() => {
 279→    if (nav.stackDepth === 0) {
 280→      setQuery('');
 281→      setFilterValue('all');
 282→      setSelectedIndex(0);
 283→      setActionsOpen(false);
 284→      setQuickLookOpen(false);
 285→    }
 286→  }, [nav.stackDepth]);
 287→
 288→  const registrySections = useMemo(() => getSections(), []);
 289→
 290→  const filtered = useMemo(() => {
 291→    let sections = registrySections;
 292→    if (filterValue === 'commands') {
 293→      sections = sections.filter(
 294→        s => s.title === 'Suggestions' || s.title === 'Commands',
 295→      );
 296→    } else if (filterValue === 'applications') {
 297→      sections = sections.filter(s => s.title === 'Applications');
 298→    }
 299→
 300→    const result = query ? searchCommands(query) : sections;
 301→
 302→    const filteredResult = query
 303→      ? result
 304→          .map(s => {
 305→            if (filterValue === 'commands') {
 306→              return s.title === 'Suggestions' || s.title === 'Commands'
 307→                ? s
 308→                : {
 309→                    ...s,
 310→                    items: [],
 311→                  };
 312→            }
 313→            if (filterValue === 'applications') {
 314→              return s.title === 'Applications'
 315→                ? s
 316→                : {
 317→                    ...s,
 318→                    items: [],
 319→                  };
 320→            }
 321→            return s;
 322→          })
 323→          .filter(s => s.items.length > 0)
 324→      : result;
 325→
 326→    const allFlatItems = sections.flatMap(s => s.items);
 327→    const favoriteItems = favoriteIds
 328→      .map(id => allFlatItems.find(item => item.id === id))
 329→      .filter((item): item is ListItemData => !!item);
 330→
 331→    if (query) {
 332→      const lower = query.toLowerCase();
 333→      const filteredFavs = favoriteItems.filter(
 334→        item =>
 335→          item.title.toLowerCase().includes(lower) ||
 336→          item.subtitle?.toLowerCase().includes(lower),
 337→      );
 338→      if (filteredFavs.length > 0) {
 339→        const favIds = new Set(filteredFavs.map(f => f.id));
 340→        const dedupedSections = filteredResult
 341→          .map(s => ({
 342→            ...s,
 343→            items: s.items.filter(item => !favIds.has(item.id)),
 344→          }))
 345→          .filter(s => s.items.length > 0);
 346→        return [
 347→          {
 348→            title: 'Favorites',
 349→            items: filteredFavs,
 350→          },
 351→          ...dedupedSections,
 352→        ];
 353→      }
 354→      return filteredResult;
 355→    }
 356→
 357→    if (favoriteItems.length > 0) {
 358→      const favIds = new Set(favoriteIds);
 359→      const dedupedSections = filteredResult
 360→        .map(s => ({
 361→          ...s,
 362→          items: s.items.filter(item => !favIds.has(item.id)),
 363→        }))
 364→        .filter(s => s.items.length > 0);
 365→      return [
 366→        {
 367→          title: 'Favorites',
 368→          items: favoriteItems,
 369→        },
 370→        ...dedupedSections,
 371→      ];
 372→    }
 373→
 374→    return filteredResult;
 375→  }, [
 376→    query,
 377→    filterValue,
 378→    favoriteIds,
 379→    registrySections,
 380→  ]);
 381→
 382→  const calculatorResult = useMemo(() => {
 383→    if (!isRoot || !query.trim()) return null;
 384→    return evaluate(query);
 385→  }, [
 386→    query,
 387→    isRoot,
 388→  ]);
 389→
 390→  const allItems = useMemo(() => {
 391→    const items = flattenItems(filtered);
 392→    if (calculatorResult) {
 393→      const calcItem: ListItemData = {
 394→        id: '__calculator__',
 395→        title: `= ${calculatorResult}`,
 396→        subtitle: query.trim(),
 397→        icon: <CalculatorIcon />,
 398→      };
 399→      return [
 400→        calcItem,
 401→        ...items,
 402→      ];
 403→    }
 404→    return items;
 405→  }, [
 406→    filtered,
 407→    calculatorResult,
 408→    query,
 409→  ]);
 410→
 411→  const selectedItem = isRoot ? allItems[selectedIndex] : undefined;
 412→
 413→  const handleQueryChange = useCallback((value: string) => {
 414→    setQuery(value);
 415→    setSelectedIndex(0);
 416→    setActionsOpen(false);
 417→  }, []);
 418→
 419→  const handleFilterChange = useCallback((value: string) => {
 420→    setFilterValue(value);
 421→    setSelectedIndex(0);
 422→  }, []);
 423→
 424→  const handleActiveIndexChange = useCallback((index: number) => {
 425→    setSelectedIndex(index);
 426→    setActionsOpen(false);
 427→  }, []);
 428→
 429→  const handleDrillIn = useCallback(() => {
 430→    const item = allItems[selectedIndex];
 431→    if (!item) return;
 432→
 433→    setActionsOpen(false);
 434→
 435→    if (item.id === '__calculator__') {
 436→      showHUD({
 437→        icon: <ClipboardHUDIcon />,
 438→        title: `Copied ${calculatorResult}`,
 439→      });
 440→      return;
 441→    }
 442→
 443→    const cmd = getCommand(item.id);
 444→
 445→    if (cmd?.component) {
 446→      push(cmd.name, {
 447→        type: 'command',
 448→        commandId: cmd.id,
 449→      });
 450→      setQuery('');
 451→      setSelectedIndex(0);
 452→    } else if (item.detail) {
 453→      push(item.title, {
 454→        type: 'detail',
 455→        item,
 456→      });
 457→      setQuery('');
 458→      showToast({
 459→        style: 'success',
 460→        title: `Opened ${item.title}`,
 461→      });
 462→    } else {
 463→      showToast({
 464→        style: 'success',
 465→        title: `Opened ${item.title}`,
 466→      });
 467→    }
 468→  }, [
 469→    allItems,
 470→    selectedIndex,
 471→    showToast,
 472→    showHUD,
 473→    calculatorResult,
 474→    push,
 475→  ]);
 476→
 477→  const toggleActions = useCallback(() => {
 478→    setActionsOpen(prev => !prev);
 479→  }, []);
 480→
 481→  const closeActions = useCallback(() => {
 482→    setActionsOpen(false);
 483→  }, []);
 484→
 485→  useKeyboardShortcut(
 486→    {
 487→      key: 'k',
 488→      meta: true,
 489→    },
 490→    toggleActions,
 491→    { enabled: !isFullView },
 492→  );
 493→
 494→  const handleToggleFavorite = useCallback(() => {
 495→    if (!selectedItem || selectedItem.id === '__calculator__') {
 496→      return;
 497→    }
 498→    const wasAlreadyFavorite = isFavorite(selectedItem.id);
 499→    toggleFavorite(selectedItem.id);
 500→    showHUD({
 501→      icon: <StarFilledIcon />,
 502→      title: wasAlreadyFavorite
 503→        ? 'Removed from Favorites'
 504→        : 'Added to Favorites',
 505→    });
 506→  }, [
 507→    selectedItem,
 508→    toggleFavorite,
 509→    isFavorite,
 510→    showHUD,
 511→  ]);
 512→
 513→  useKeyboardShortcut(
 514→    {
 515→      key: 'f',
 516→      meta: true,
 517→      shift: true,
 518→    },
 519→    handleToggleFavorite,
 520→    { enabled: isRoot && !!selectedItem },
 521→  );
 522→
 523→  const handleMoveFavoriteUp = useCallback(() => {
 524→    if (!selectedItem || !isFavorite(selectedItem.id)) return;
 525→    moveFavorite(selectedItem.id, 'up');
 526→    setSelectedIndex(prev => Math.max(0, prev - 1));
 527→  }, [
 528→    selectedItem,
 529→    isFavorite,
 530→    moveFavorite,
 531→  ]);
 532→
 533→  const handleMoveFavoriteDown = useCallback(() => {
 534→    if (!selectedItem || !isFavorite(selectedItem.id)) return;
 535→    moveFavorite(selectedItem.id, 'down');
 536→    setSelectedIndex(prev => prev + 1);
 537→  }, [
 538→    selectedItem,
 539→    isFavorite,
 540→    moveFavorite,
 541→  ]);
 542→
 543→  useKeyboardShortcut(
 544→    {
 545→      key: 'ArrowUp',
 546→      meta: true,
 547→      alt: true,
 548→    },
 549→    handleMoveFavoriteUp,
 550→    {
 551→      enabled: isRoot && !!selectedItem && isFavorite(selectedItem.id),
 552→    },
 553→  );
 554→
 555→  useKeyboardShortcut(
 556→    {
 557→      key: 'ArrowDown',
 558→      meta: true,
 559→      alt: true,
 560→    },
 561→    handleMoveFavoriteDown,
 562→    {
 563→      enabled: isRoot && !!selectedItem && isFavorite(selectedItem.id),
 564→    },
 565→  );
 566→
 567→  const openSettings = useCallback(() => {
 568→    const settingsCmd = getCommand('settings');
 569→    if (settingsCmd) {
 570→      const isAlreadySettings =
 571→        currentNavData?.type === 'command' &&
 572→        currentNavData.commandId === 'settings';
 573→      if (!isAlreadySettings) {
 574→        push('Settings', {
 575→          type: 'command',
 576→          commandId: 'settings',
 577→        });
 578→        setQuery('');
 579→        setSelectedIndex(0);
 580→        setActionsOpen(false);
 581→      }
 582→    }
 583→  }, [
 584→    currentNavData,
 585→    push,
 586→  ]);
 587→
 588→  useKeyboardShortcut(
 589→    {
 590→      key: ',',
 591→      meta: true,
 592→    },
 593→    openSettings,
 594→  );
 595→
 596→  const toggleQuickLook = useCallback(() => {
 597→    setQuickLookOpen(prev => !prev);
 598→  }, []);
 599→
 600→  const closeQuickLook = useCallback(() => {
 601→    setQuickLookOpen(false);
 602→  }, []);
 603→
 604→  useKeyboardShortcut(
 605→    {
 606→      key: 'y',
 607→      meta: true,
 608→    },
 609→    toggleQuickLook,
 610→    { enabled: isRoot && !!selectedItem?.detail },
 611→  );
 612→
 613→  useEffect(() => {
 614→    if (!isRoot || !selectedItem?.detail) return;
 615→
 616→    function handleSpaceBar(e: KeyboardEvent) {
 617→      if (e.key !== ' ' || e.metaKey || e.ctrlKey || e.altKey) {
 618→        return;
 619→      }
 620→      if (query !== '') return;
 621→
 622→      e.preventDefault();
 623→      e.stopPropagation();
 624→      setQuickLookOpen(prev => !prev);
 625→    }
 626→
 627→    window.addEventListener('keydown', handleSpaceBar);
 628→    return () => window.removeEventListener('keydown', handleSpaceBar);
 629→  }, [
 630→    isRoot,
 631→    selectedItem?.detail,
 632→    query,
 633→  ]);
 634→
 635→  const isCalculatorSelected = selectedItem?.id === '__calculator__';
 636→  const detail = isCalculatorSelected ? undefined : selectedItem?.detail;
 637→
 638→  const dropdownSections = useMemo(
 639→    () => [
 640→      {
 641→        title: 'Primary Actions',
 642→        actions: [
 643→          {
 644→            label: isCalculatorSelected ? 'Copy Result' : 'Open',
 645→            shortcut: <Kbd keys={['↵']} />,
 646→            onClick: () => {
 647→              if (isCalculatorSelected && calculatorResult) {
 648→                showHUD({
 649→                  icon: <ClipboardHUDIcon />,
 650→                  title: `Copied ${calculatorResult}`,
 651→                });
 652→              } else if (selectedItem) {
 653→                showToast({
 654→                  style: 'success' as const,
 655→                  title: `Opened ${selectedItem.title}`,
 656→                });
 657→              }
 658→            },
 659→          },
 660→          {
 661→            label: 'Quick Look',
 662→            shortcut: (
 663→              <Kbd
 664→                keys={[
 665→                  '⌘',
 666→                  'Y',
 667→                ]}
 668→              />
 669→            ),
 670→            onClick: () => {
 671→              if (selectedItem?.detail) {
 672→                setActionsOpen(false);
 673→                setQuickLookOpen(prev => !prev);
 674→              }
 675→            },
 676→          },
 677→          ...(!isCalculatorSelected && selectedItem
 678→            ? [
 679→                {
 680→                  label:
 681→                    selectedItem && isFavorite(selectedItem.id)
 682→                      ? 'Remove from Favorites'
 683→                      : 'Add to Favorites',
 684→                  shortcut: (
 685→                    <Kbd
 686→                      keys={[
 687→                        '⌘',
 688→                        '⇧',
 689→                        'F',
 690→                      ]}
 691→                    />
 692→                  ),
 693→                  onClick: () => {
 694→                    if (selectedItem) {
 695→                      setActionsOpen(false);
 696→                      handleToggleFavorite();
 697→                    }
 698→                  },
 699→                },
 700→              ]
 701→            : []),
 702→        ],
 703→      },
 704→      {
 705→        title: 'Copy Actions',
 706→        actions: [
 707→          {
 708→            label: 'Copy Name',
 709→            shortcut: (
 710→              <Kbd
 711→                keys={[
 712→                  '⌘',
 713→                  'C',
 714→                ]}
 715→              />
 716→            ),
 717→            onClick: () => {
 718→              if (selectedItem) {
 719→                showHUD({
 720→                  icon: <CheckIcon />,
 721→                  title: 'Copied to Clipboard',
 722→                });
 723→              }
 724→            },
 725→          },
 726→          {
 727→            label: 'Copy As...',
 728→            submenu: [
 729→              {
 730→                actions: [
 731→                  {
 732→                    label: 'Copy as Markdown',
 733→                    onClick: () => {
 734→                      if (selectedItem) {
 735→                        showHUD({
 736→                          icon: <CheckIcon />,
 737→                          title: 'Copied as Markdown',
 738→                        });
 739→                      }
 740→                    },
 741→                  },
 742→                  {
 743→                    label: 'Copy as JSON',
 744→                    onClick: () => {
 745→                      if (selectedItem) {
 746→                        showHUD({
 747→                          icon: <CheckIcon />,
 748→                          title: 'Copied as JSON',
 749→                        });
 750→                      }
 751→                    },
 752→                  },
 753→                  {
 754→                    label: 'Copy as Plain Text',
 755→                    onClick: () => {
 756→                      if (selectedItem) {
 757→                        showHUD({
 758→                          icon: <CheckIcon />,
 759→                          title: 'Copied as Plain Text',
 760→                        });
 761→                      }
 762→                    },
 763→                  },
 764→                ],
 765→              },
 766→            ],
 767→          },
 768→        ],
 769→      },
 770→      {
 771→        title: 'Danger Zone',
 772→        actions: [
 773→          {
 774→            label: 'Delete',
 775→            shortcut: (
 776→              <Kbd
 777→                keys={[
