138→function loadInitialEntries(): ClipboardEntry[] {
139→  const pinState = storageGet(PIN_STATE_KEY, isBooleanRecord) ?? {};
140→  const deleted = new Set(storageGet(DELETED_KEY, isStringArray) ?? []);
141→  return MOCK_CLIPBOARD_ENTRIES.filter(e => !deleted.has(e.id)).map(e => ({
142→    ...e,
143→    pinned: e.id in pinState ? pinState[e.id]! : e.pinned,
144→  }));
145→}
