147→function saveEntryState(entries: ClipboardEntry[]) {
148→  const pinState: Record<string, boolean> = {};
149→  for (const e of entries) {
150→    pinState[e.id] = e.pinned;
151→  }
152→  storageSet(PIN_STATE_KEY, pinState);
153→
154→  const allIds = new Set(MOCK_CLIPBOARD_ENTRIES.map(e => e.id));
155→  const currentIds = new Set(entries.map(e => e.id));
156→  const deleted = [...allIds].filter(id => !currentIds.has(id));
157→  storageSet(DELETED_KEY, deleted);
158→}
