 58→function loadRecentEmojis(): string[] {
 59→  const stored = storageGet(STORAGE_KEY, isStringArray);
 60→  if (stored) return stored;
 61→
 62→  try {
 63→    const legacy = localStorage.getItem('emoji-picker-recent');
 64→    if (legacy) {
 65→      const parsed: unknown = JSON.parse(legacy);
 66→      if (isStringArray(parsed)) {
 67→        storageSet(STORAGE_KEY, parsed);
 68→        localStorage.removeItem('emoji-picker-recent');
 69→        return parsed;
 70→      }
 71→    }
 72→  } catch {
 73→    // unavailable
 74→  }
 75→  return [];
 76→}
