101→export function EmojiPickerView() {
102→  const nav = useNavigation();
103→  const [query, setQuery] = useState('');
104→  const [filterValue, setFilterValue] = useState('all');
105→  const [activeIndex, setActiveIndex] = useState(0);
106→  const [actionsOpen, setActionsOpen] = useState(false);
107→  const [recentChars, setRecentChars] = useState<string[]>(loadRecentEmojis);
108→  const { items: hudItems, show: showHUD } = useHUD();
109→  const containerRef = useRef<HTMLDivElement>(null);
110→
111→  const emojiLookup = useMemo(() => {
112→    const map = new Map<string, EmojiEntry>();
113→    for (const e of MOCK_EMOJIS) {
114→      map.set(e.char, e);
115→    }
116→    return map;
117→  }, []);
118→
119→  const recentEmojis = useMemo(
120→    () =>
121→      recentChars
122→        .map(char => emojiLookup.get(char))
123→        .filter((e): e is EmojiEntry => e !== undefined),
124→    [
125→      recentChars,
126→      emojiLookup,
127→    ],
128→  );
129→
130→  const filtered = useMemo(() => {
131→    let emojis = MOCK_EMOJIS;
132→    if (filterValue !== 'all') {
133→      emojis = emojis.filter(e => e.category === filterValue);
134→    }
135→    if (query) {
136→      const lower = query.toLowerCase();
137→      emojis = emojis.filter(
138→        e =>
139→          e.name.toLowerCase().includes(lower) ||
140→          e.keywords.some(k => k.includes(lower)) ||
141→          e.char === query,
142→      );
143→    }
144→    return emojis;
145→  }, [
146→    query,
147→    filterValue,
148→  ]);
149→
150→  const sections = useMemo(() => {
151→    const result: EmojiSection[] = [];
152→
153→    if (!query && filterValue === 'all' && recentEmojis.length > 0) {
154→      result.push({
155→        title: 'Recently Used',
156→        emojis: recentEmojis,
157→      });
158→    }
159→
160→    const grouped = new Map<EmojiCategory, EmojiEntry[]>();
161→    for (const emoji of filtered) {
162→      const existing = grouped.get(emoji.category);
163→      if (existing) {
164→        existing.push(emoji);
165→      } else {
166→        grouped.set(emoji.category, [emoji]);
167→      }
168→    }
169→
170→    for (const cat of EMOJI_CATEGORY_ORDER) {
171→      const items = grouped.get(cat);
172→      if (items && items.length > 0) {
173→        result.push({
174→          title: EMOJI_CATEGORY_LABELS[cat],
175→          emojis: items,
176→        });
177→      }
178→    }
179→
180→    return result;
181→  }, [
182→    filtered,
183→    query,
184→    filterValue,
185→    recentEmojis,
186→  ]);
187→
188→  const flatEmojis = useMemo(() => sections.flatMap(s => s.emojis), [sections]);
189→  const totalCount = flatEmojis.length;
190→
191→  useEffect(() => {
192→    if (totalCount === 0) {
193→      setActiveIndex(0);
194→    } else if (activeIndex >= totalCount) {
195→      setActiveIndex(totalCount - 1);
196→    }
197→  }, [
198→    totalCount,
199→    activeIndex,
200→  ]);
201→
202→  useEffect(() => {
203→    const container = containerRef.current;
204→    if (!container) return;
205→    const el = container.querySelector<HTMLElement>(
206→      `[data-emoji-index="${activeIndex}"]`,
207→    );
208→    el?.scrollIntoView({ block: 'nearest' });
209→  }, [activeIndex]);
210→
211→  const selectedEmoji = flatEmojis[activeIndex];
212→
213→  const addToRecent = useCallback((char: string) => {
214→    setRecentChars(prev => {
215→      const next = [
216→        char,
217→        ...prev.filter(c => c !== char),
218→      ].slice(0, MAX_RECENT);
219→      storageSet(STORAGE_KEY, next);
220→      return next;
221→    });
222→  }, []);
223→
224→  const handleCopyEmoji = useCallback(
225→    (emoji?: EmojiEntry) => {
226→      const target = emoji ?? selectedEmoji;
227→      if (!target) return;
228→      navigator.clipboard.writeText(target.char).catch(() => {});
229→      setActionsOpen(false);
230→      addToRecent(target.char);
231→      showHUD({
232→        icon: <CopyHUDIcon />,
233→        title: `Copied ${target.char}`,
234→      });
235→    },
236→    [
237→      selectedEmoji,
238→      showHUD,
239→      addToRecent,
240→    ],
241→  );
242→
243→  const handleQueryChange = useCallback((value: string) => {
244→    setQuery(value);
245→    setActiveIndex(0);
246→    setActionsOpen(false);
247→  }, []);
248→
249→  const handleFilterChange = useCallback((value: string) => {
250→    setFilterValue(value);
251→    setActiveIndex(0);
252→  }, []);
253→
254→  const toggleActions = useCallback(() => {
255→    setActionsOpen(prev => !prev);
256→  }, []);
257→
258→  const closeActions = useCallback(() => {
259→    setActionsOpen(false);
260→  }, []);
261→
262→  useKeyboardShortcut(
263→    {
264→      key: 'k',
265→      meta: true,
266→    },
267→    toggleActions,
268→  );
269→  useKeyboardShortcut(
270→    {
271→      key: 'c',
272→      meta: true,
273→    },
274→    () => handleCopyEmoji(),
275→  );
276→
277→  useEffect(() => {
278→    function handleKeyDown(e: KeyboardEvent) {
279→      if (totalCount === 0) return;
280→      if (actionsOpen) return;
281→      if (e.metaKey || e.ctrlKey || e.altKey) return;
282→
283→      const isTextInput =
284→        e.target instanceof HTMLInputElement ||
285→        e.target instanceof HTMLTextAreaElement;
286→
287→      switch (e.key) {
288→        case 'ArrowRight': {
289→          if (isTextInput) return;
290→          e.preventDefault();
291→          setActiveIndex(prev => (prev + 1 < totalCount ? prev + 1 : 0));
292→          break;
293→        }
294→        case 'ArrowLeft': {
295→          if (isTextInput) return;
296→          e.preventDefault();
297→          setActiveIndex(prev => (prev - 1 >= 0 ? prev - 1 : totalCount - 1));
298→          break;
299→        }
300→        case 'ArrowDown': {
301→          e.preventDefault();
302→          setActiveIndex(prev => {
303→            const sectionInfo = getSectionInfo(prev);
304→            if (!sectionInfo) return prev;
305→            const { sectionStart, sectionLength } = sectionInfo;
306→            const posInSection = prev - sectionStart;
307→            const row = Math.floor(posInSection / COLUMNS);
308→            const col = posInSection % COLUMNS;
309→            const sectionRows = Math.ceil(sectionLength / COLUMNS);
310→
311→            if (row + 1 < sectionRows) {
312→              const nextIdx = sectionStart + (row + 1) * COLUMNS + col;
313→              return nextIdx < sectionStart + sectionLength
314→                ? nextIdx
315→                : sectionStart + sectionLength - 1;
316→            }
317→
318→            const nextSectionStart = sectionStart + sectionLength;
319→            if (nextSectionStart < totalCount) {
320→              const nextInfo = getSectionInfo(nextSectionStart);
321→              if (!nextInfo) return prev;
322→              const targetIdx = nextSectionStart + col;
323→              return targetIdx < nextSectionStart + nextInfo.sectionLength
324→                ? targetIdx
325→                : nextSectionStart + nextInfo.sectionLength - 1;
326→            }
327→
328→            return prev;
329→          });
330→          break;
331→        }
332→        case 'ArrowUp': {
333→          e.preventDefault();
334→          setActiveIndex(prev => {
335→            const sectionInfo = getSectionInfo(prev);
336→            if (!sectionInfo) return prev;
337→            const { sectionStart } = sectionInfo;
338→            const posInSection = prev - sectionStart;
339→            const row = Math.floor(posInSection / COLUMNS);
340→            const col = posInSection % COLUMNS;
341→
342→            if (row > 0) {
343→              return sectionStart + (row - 1) * COLUMNS + col;
344→            }
345→
346→            if (sectionStart > 0) {
347→              const prevSectionEnd = sectionStart - 1;
348→              const prevInfo = getSectionInfo(prevSectionEnd);
349→              if (!prevInfo) return prev;
350→              const prevSectionRows = Math.ceil(
351→                prevInfo.sectionLength / COLUMNS,
352→              );
353→              const lastRowStart =
354→                prevInfo.sectionStart + (prevSectionRows - 1) * COLUMNS;
355→              const targetIdx = lastRowStart + col;
356→              return targetIdx < prevInfo.sectionStart + prevInfo.sectionLength
357→                ? targetIdx
358→                : prevInfo.sectionStart + prevInfo.sectionLength - 1;
359→            }
360→
361→            return prev;
362→          });
363→          break;
364→        }
365→        case 'Enter': {
366→          e.preventDefault();
367→          handleCopyEmoji();
368→          break;
369→        }
370→      }
371→    }
372→
373→    window.addEventListener('keydown', handleKeyDown);
374→    return () => window.removeEventListener('keydown', handleKeyDown);
375→  }, [
376→    totalCount,
377→    actionsOpen,
378→    handleCopyEmoji,
379→    sections,
380→  ]);
381→
382→  const sectionBoundaries = useMemo(() => {
