450→
451→  const activeDescendantId =
452→    totalCount > 0 ? `emoji-item-${activeIndex}` : undefined;
453→
454→  return (
455→    <>
456→      <SearchBar
457→        value={query}
458→        onChange={handleQueryChange}
459→        placeholder="Search Emoji..."
460→        activeDescendantId={activeDescendantId}
461→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
462→        dropdown={
