 96→const SNIPPETS_KEY = 'snippets';
 97→
 98→interface StoredSnippet {
 99→  id: string;
100→  name: string;
101→  keyword: string;
102→  content: string;
103→  category: string;
104→  tags: {
105→    text: string;
106→    color?: string;
107→  }[];
108→  createdAt: string;
109→}
110→
111→function isStoredTag(value: unknown): value is {
112→  text: string;
113→  color?: string;
114→} {
115→  if (!isRecord(value)) return false;
116→  if (typeof value.text !== 'string') return false;
117→  if ('color' in value && typeof value.color !== 'string') {
118→    return false;
119→  }
120→  return true;
121→}
122→
123→function isStoredSnippetArray(value: unknown): value is StoredSnippet[] {
124→  if (!Array.isArray(value)) return false;
125→  return value.every(
126→    v =>
127→      isRecord(v) &&
128→      typeof v.id === 'string' &&
129→      typeof v.name === 'string' &&
130→      typeof v.keyword === 'string' &&
131→      typeof v.content === 'string' &&
132→      typeof v.category === 'string' &&
133→      typeof v.createdAt === 'string' &&
134→      Array.isArray(v.tags) &&
135→      v.tags.every(isStoredTag),
136→  );
137→}
138→
139→function serializeEntries(entries: SnippetEntry[]): StoredSnippet[] {
140→  return entries.map(e => ({
141→    ...e,
142→    createdAt: e.createdAt.toISOString(),
143→  }));
144→}
145→
146→const TAG_COLOR_NAMES = new Set<string>(Object.keys(TAG_COLOR_HEX));
147→
148→function isTagColor(value: string): value is TagColor {
149→  return TAG_COLOR_NAMES.has(value);
150→}
151→
152→function deserializeEntries(stored: StoredSnippet[]): SnippetEntry[] {
153→  return stored.map(s => {
154→    const parsed = new Date(s.createdAt);
155→    const createdAt = Number.isNaN(parsed.getTime()) ? new Date() : parsed;
156→    return {
157→      ...s,
158→      category: isSnippetCategory(s.category) ? s.category : 'general',
159→      tags: s.tags.map(t => ({
160→        text: t.text,
161→        color: t.color && isTagColor(t.color) ? t.color : undefined,
162→      })),
163→      createdAt,
164→    };
165→  });
166→}
167→
168→function loadSnippets(): SnippetEntry[] {
169→  const stored = storageGet(SNIPPETS_KEY, isStoredSnippetArray);
170→  if (stored) return deserializeEntries(stored);
171→  return MOCK_SNIPPET_ENTRIES;
172→}
173→
174→function saveSnippets(entries: SnippetEntry[]) {
175→  storageSet(SNIPPETS_KEY, serializeEntries(entries));
